        for (i, val) in values.into_iter().enumerate() {
            if let Some(member) = members.get(i) {
                stmts.push(Stmt::Expr(Expr::MemberAssign {
                    object: Box::new(Expr::Ident(name.clone())),
                    member: member.name.clone(),
                    value: Box::new(val),
                }));
            }
        }
    }

    Ok(Stmt::Block(Block { stmts }))
}

